const { SQSClient, DeleteMessageCommand } = require('@aws-sdk/client-sqs');
const { DynamoDBClient, PutItemCommand } = require('@aws-sdk/client-dynamodb');

// Initialize AWS clients
const sqsClient = new SQSClient({ region: 'your-region' });
const dynamoDbClient = new DynamoDBClient({ region: 'your-region' });

// Set up SQS queue URL and database table name
const queueUrl = 'https://sqs.your-region.amazonaws.com/your-account-id/your-queue-name';
const tableName = 'financial-transactions';

// Process messages from SQS
async function processMessages() {
  try {
    const params = { QueueUrl: queueUrl };
    const data = await sqsClient.send(new GetQueueAttributesCommand(params));
    if (data.Attributes.ApproximateNumberOfMessages > 0) {
      const receiveMessageParams = {
        QueueUrl: queueUrl,
        MaxNumberOfMessages: 10
      };

      const messages = await sqsClient.send(new ReceiveMessageCommand(receiveMessageParams));

      for (const message of messages.Messages!) {
        try {
          // Parse message content
          const transactionData = JSON.parse(message.Body);

          // Execute database update directly based on message content
          const putItemParams = {
            TableName: tableName,
            Item: {
              id: transactionData.id,
              amount: transactionData.amount,
              timestamp: new Date().toISOString()
            }
          };

          await dynamoDbClient.send(new PutItemCommand(putItemParams));

          // Delete message from SQS
          const deleteMessageParams = {
            QueueUrl: queueUrl,
            ReceiptHandle: message.ReceiptHandle!
          };
          await sqsClient.send(new DeleteMessageCommand(deleteMessageParams));
        } catch (error) {
          console.error('Error processing message:', error);
        }
      }
    }
  } catch (error) {
    console.error('Error receiving messages from SQS:', error);
  }
}

// Run the processMessages function in a loop
setInterval(processMessages, 1000); // Process messages every second